/**
 * @summary Lookup a user by their unique code
 */
export const getLookupUserByCodeUrl = (params: LookupUserByCodeParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/users/lookup?${stringifiedParams}`
    : `/api/users/lookup`;
};

export const lookupUserByCode = async (
  params: LookupUserByCodeParams,
  options?: RequestInit,
): Promise<UserPublic> => {
  return customFetch<UserPublic>(getLookupUserByCodeUrl(params), {
    ...options,
    method: "GET",
  });
};

